        '// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\n// Get a free hosted Postgres database in seconds: `npx create-db`\n\ngenerator client {\n  provider = "prisma-client"\n  output   = "./generated"\n}\n\ndatasource db {\n  provider = "postgresql"\n}\n\nenum UserRole {\n  CUSTOMER\n  ADMIN\n}\n\n// 1. User management\nmodel User {\n  id          String                @id @default(cuid())\n  name        String?\n  email       String                @unique\n  password    String // Dùng cho Login truyền thống\n  role        UserRole              @default(CUSTOMER)\n  createdAt   DateTime              @default(now())\n  updatedAt   DateTime              @updatedAt\n  orders      Order[]\n  addressBook AddressBookEntry[]\n  reminders   AnniversaryReminder[]\n}\n\n// 2. Danh mục sản phẩm (Sinh nhật, Khai trương, Hoa Hồng...)\nmodel Category {\n  id          String    @id @default(cuid())\n  name        String    @unique\n  slug        String    @unique\n  description String?\n  products    Product[]\n  createdAt   DateTime  @default(now())\n}\n\n// 3. Sản phẩm hoa mẫu\nmodel Product {\n  id          String        @id @default(cuid())\n  name        String\n  slug        String        @unique\n  description String\n  price       Float // Giá gốc hoặc giá size tiêu chuẩn\n  images      String[] // Mảng chứa các URL ảnh từ Cloudinary/S3\n  stock       Int           @default(0) // Số lượng bó sẵn có\n  isFeatured  Boolean       @default(false) // Hiển thị trang chủ\n  createdAt   DateTime      @default(now())\n  updatedAt   DateTime      @updatedAt\n  categoryId  String\n  category    Category      @relation(fields: [categoryId], references: [id])\n  orderItems  OrderItem[]\n  stems       ProductStem[] // Công thức cắm hoa từ các cành hoa raw\n}\n\n// 3.5. Cành hoa raw trong kho đông lạnh (Quản lý stem-level inventory)\nmodel Stem {\n  id          String              @id @default(cuid())\n  name        String              @unique // Tên cành hoa, vd: Red Rose, Yellow Tulip, Lily\n  color       String // Màu chủ đạo để filter\n  stock       Int                 @default(0) // Số lượng cành hiện có trong tủ bảo quản\n  criticalMin Int                 @default(10) // Ngưỡng cảnh báo sắp hết hoa\n  createdAt   DateTime            @default(now())\n  updatedAt   DateTime            @updatedAt\n  products    ProductStem[]\n  customItems CustomBouquetStem[]\n}\n\n// Bảng liên kết công thức cắm hoa\nmodel ProductStem {\n  id        String  @id @default(cuid())\n  productId String\n  product   Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n  stemId    String\n  stem      Stem    @relation(fields: [stemId], references: [id], onDelete: Cascade)\n  quantity  Int // Số lượng cành cần dùng cho 1 bó mẫu\n\n  @@unique([productId, stemId])\n}\n\n// 4. Đơn hàng (Đặc thù ngành hoa)\nmodel Order {\n  id          String      @id @default(cuid())\n  orderNumber String      @unique // Mã đơn hàng hiển thị cho khách (VD: FLW-123456)\n  createdAt   DateTime    @default(now())\n  updatedAt   DateTime    @updatedAt\n  status      OrderStatus @default(PENDING)\n  totalAmount Float\n\n  // Thông tin người MUA\n  buyerName  String\n  buyerPhone String\n  buyerEmail String\n\n  // Thông tin người NHẬN (Đặc thù tặng quà)\n  recipientName    String\n  recipientPhone   String\n  recipientAddress String\n  isAnonymous      Boolean @default(false) // Giao hàng ẩn danh\n\n  // Lời chúc và Thời gian giao (Đặc thù ngành hoa)\n  cardMessage  String? // Lời chúc in trên thiệp\n  deliveryDate DateTime // Ngày giao hoa khách chọn\n  deliverySlot String // Khung giờ giao (VD: "08:00 - 10:00")\n\n  // Thanh toán\n  paymentMethod    String // COD, VNPAY, MOMO, PAYOS\n  paymentStatus    PaymentStatus @default(UNPAID)\n  paymentSessionId String? // ID session thanh toán để webhook tracking\n\n  // Quan hệ\n  userId         String? // Có thể null nếu khách mua không cần tài khoản (Guest Checkout)\n  user           User?           @relation(fields: [userId], references: [id], onDelete: SetNull)\n  items          OrderItem[]\n  customBouquets CustomBouquet[]\n}\n\n// 5. Chi tiết sản phẩm trong đơn hàng\nmodel OrderItem {\n  id       String @id @default(cuid())\n  quantity Int\n  price    Float // Lưu giá tại thời điểm mua\n\n  orderId   String\n  order     Order   @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  productId String\n  product   Product @relation(fields: [productId], references: [id])\n}\n\n// 6. Bó hoa tự thiết kế (Custom Bouquet) do khách tự chọn cành\nmodel CustomBouquet {\n  id        String              @id @default(cuid())\n  price     Float // Giá tổng của bó tự chế\n  quantity  Int                 @default(1)\n  wrapPaper String // Loại giấy gói chọn\n  ribbon    String // Loại ruy băng chọn\n  orderId   String\n  order     Order               @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  stems     CustomBouquetStem[]\n}\n\nmodel CustomBouquetStem {\n  id              String        @id @default(cuid())\n  customBouquetId String\n  customBouquet   CustomBouquet @relation(fields: [customBouquetId], references: [id], onDelete: Cascade)\n  stemId          String\n  stem            Stem          @relation(fields: [stemId], references: [id])\n  quantity        Int // Số lượng cành khách chọn cho loại hoa này\n}\n\n// 7. Sổ địa chỉ (Lưu danh sách người nhận quà hay tặng)\nmodel AddressBookEntry {\n  id               String   @id @default(cuid())\n  userId           String\n  user             User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  label            String // Nhãn gợi nhớ, ví dụ: "Vợ yêu", "Mẹ", "Sếp"\n  recipientName    String\n  recipientPhone   String\n  recipientAddress String\n  createdAt        DateTime @default(now())\n}\n\n// 8. Nhắc nhở kỷ niệm\nmodel AnniversaryReminder {\n  id                String   @id @default(cuid())\n  userId            String\n  user              User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  title             String // Ví dụ: "Kỷ niệm ngày cưới", "Sinh nhật Vợ"\n  recipientName     String\n  date              DateTime // Ngày tháng kỷ niệm hàng năm\n  lastTriggeredYear Int? // Năm gần nhất đã gửi thông báo / code giảm giá\n  createdAt         DateTime @default(now())\n}\n\n// 9. Mã giảm giá (Coupon)\nmodel Coupon {\n  code         String     @id // Mã giảm giá, ví dụ: "HAPPYWOMANDAY"\n  discountType CouponType @default(PERCENTAGE)\n  value        Float // Giá trị giảm (Ví dụ 15 cho 15% hoặc 50000 cho 50k VND)\n  maxUses      Int? // Số lượt dùng tối đa (null nếu không giới hạn)\n  usedCount    Int        @default(0) // Số lượt đã dùng\n  active       Boolean    @default(true) // Trạng thái kích hoạt\n  expiresAt    DateTime? // Ngày hết hạn\n}\n\nenum CouponType {\n  PERCENTAGE\n  FIXED\n}\n\nenum OrderStatus {\n  PENDING // Chờ xử lý\n  CONFIRMED // Đã xác nhận đơn\n  PROCESSING // Đang cắm hoa\n  DELIVERING // Đang giao\n  COMPLETED // Đã giao hoa thành công\n  CANCELLED // Đã hủy\n}\n\nenum PaymentStatus {\n  UNPAID\n  PAID\n  REFUNDED\n}\n',
